PREFIX ficr: <https://w3id.org/ficr#>
PREFIX bot: <https://w3id.org/bot#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?building (COUNT(DISTINCT ?storey) AS ?storeys) (COUNT(DISTINCT ?space) AS ?spaces)
WHERE {
  ?building a ficr:MultiStoreyBuilding .
  OPTIONAL { ?building bot:hasStorey ?storey . }
  OPTIONAL { ?building bot:hasStorey/bot:hasSpace ?space . }
}
GROUP BY ?building


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX bot: <https://w3id.org/bot#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?storey ?label ?kind ?elevation (COUNT(DISTINCT ?space) AS ?spaces)
WHERE {
  ?building a ficr:MultiStoreyBuilding ; bot:hasStorey ?storey .
  ?storey a ?kind .
  FILTER(?kind IN (ficr:BasementStorey, ficr:GroundAndAboveStorey))
  OPTIONAL { ?storey rdfs:label ?label . }
  OPTIONAL { ?storey ficr:hasElevation ?elevation . }
  OPTIONAL { ?storey bot:hasSpace ?space . }
}
GROUP BY ?storey ?label ?kind ?elevation
ORDER BY ?elevation


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX bot: <https://w3id.org/bot#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?space ?label ?storey ?usage ?area
WHERE {
  ?storey bot:hasSpace ?space .
  ?space a ?spaceType .
  FILTER(?spaceType IN (ficr:RoomSpace, ficr:StairSpace, ficr:RoofSpace))
  OPTIONAL { ?space rdfs:label ?label . }
  OPTIONAL { ?space ficr:hasSpaceUsage ?usage . }
  OPTIONAL { ?space ficr:hasArea ?area . }
}
ORDER BY ?label


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX bot: <https://w3id.org/bot#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?space ?spaceLabel ?item ?itemKind
WHERE {
  ?space ficr:hasSpaceUsage ?usage .
  OPTIONAL { ?space rdfs:label ?spaceLabel . }
  {
    ?space bot:adjacentElement ?item .
    ?item a ?t . FILTER(?t IN (ficr:Wall, ficr:ExternalWall, ficr:FloorSlab, ficr:Doorset))
    BIND("fabric" AS ?itemKind)
  } UNION {
    ?item ficr:isLocatedIn ?space .
    ?item a ?t . FILTER(?t IN (ficr:FireExtinguisher, ficr:Alarm))
    BIND("equipment" AS ?itemKind)
  }
}
ORDER BY ?spaceLabel ?itemKind


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?result (COUNT(DISTINCT ?finding) AS ?count)
WHERE {
  ?finding a ficr:ComplianceFinding ;
           ficr:hasComplianceResult ?result ;
           ficr:concernsElement ?element .
}
GROUP BY ?result
ORDER BY DESC(?count) ?result


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?element ?category ?actualREI ?requiredREI ?result
WHERE {
  ?finding a ficr:ComplianceFinding ;
           ficr:concernsElement ?element ;
           ficr:checksRequirement ?req ;
           ficr:hasComplianceResult ?result .
  # OPTIONAL: the UND-01 no-record element has no assessed REI (Undetermined);
  # it still surfaces as a finding row with an unbound actual REI.
  OPTIONAL { ?element ficr:hasActualREI ?actualREI . }
  ?req ficr:hasRequiredREI ?requiredREI .
  # Category from the inferred class; party walls are CompartmentWall.
  OPTIONAL {
    ?element a ficr:CompartmentWall . BIND("CompartmentWall" AS ?cw)
  }
  BIND(COALESCE(?cw, "Wall/Floor") AS ?category)
  # Only elements that are NOT plain external walls receive REI findings; the
  # filter guards against the materialised ExternalWall->Wall entailment.
  FILTER NOT EXISTS {
    ?element a ficr:ExternalWall .
    FILTER NOT EXISTS { ?element a ficr:CompartmentWall . }
  }
}
ORDER BY ?category ?result ?element


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?definedClass (COUNT(DISTINCT ?instance) AS ?count)
WHERE {
  VALUES ?definedClass {
    ficr:Wall ficr:ExternalWall ficr:CompartmentWall
    ficr:FloorSlab ficr:CompartmentFloor
  }
  OPTIONAL { ?instance a ?definedClass . }
}
GROUP BY ?definedClass
HAVING (COUNT(DISTINCT ?instance) > 0)
ORDER BY DESC(?count) ?definedClass


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?finding ?element ?actualREI ?req ?requiredREI ?result ?clause
WHERE {
  ?finding a ficr:ComplianceFinding ;
           ficr:concernsElement ?element ;
           ficr:checksRequirement ?req ;
           ficr:hasComplianceResult ?result .
  # OPTIONAL: the UND-01 no-record element has no assessed REI (Undetermined).
  OPTIONAL { ?element ficr:hasActualREI ?actualREI . }
  ?req ficr:hasRequiredREI ?requiredREI ;
       ficr:hasClauseReference ?clause .
  FILTER NOT EXISTS {
    ?element a ficr:ExternalWall .
    FILTER NOT EXISTS { ?element a ficr:CompartmentWall . }
  }
}
ORDER BY ?req ?result ?element


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?unit ?label ?installation (COUNT(DISTINCT ?space) AS ?coveredSpaces)
WHERE {
  ?unit a ficr:RiskUnit .
  OPTIONAL { ?unit rdfs:label ?label . }
  OPTIONAL { ?unit ficr:hasInstallationStatus ?installation . }
  OPTIONAL { ?unit ficr:coversSpatialZone ?space . }
}
GROUP BY ?unit ?label ?installation
ORDER BY ?label


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?unit ?conditionState (COUNT(DISTINCT ?ba) AS ?count)
WHERE {
  ?ba a ficr:BoundaryAssumption ;
      ficr:appliesToRiskUnit ?unit ;
      ficr:hasConditionState ?conditionState .
}
GROUP BY ?unit ?conditionState
ORDER BY ?unit ?conditionState


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>

SELECT ?ba ?unit ?conditionState ?evidence ?evidenceType ?title ?gap
WHERE {
  ?ba a ficr:BoundaryAssumption ;
      ficr:appliesToRiskUnit ?unit ;
      ficr:hasConditionState ?conditionState .
  OPTIONAL {
    ?ba ficr:supportedByEvidence ?evidence .
    OPTIONAL {
      ?evidence a ?evidenceType .
      FILTER(?evidenceType IN (ficr:CertificateEvidence, ficr:DrawingEvidence,
                               ficr:ObservedEvidence, ficr:InspectionReportEvidence))
    }
    OPTIONAL { ?evidence ficr:documentTitle ?title . }
  }
  BIND(IF(!BOUND(?evidence) && ?conditionState = ficr:Unknown,
          "EVIDENCE GAP", "--") AS ?gap)
}
ORDER BY ?unit ?ba


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?ba ?evidenceStatus ?hasEvidence
WHERE {
  ?ba a ficr:BoundaryAssumption ;
      ficr:hasEvidenceStatus ?evidenceStatus .
  OPTIONAL { ?ba ficr:supportedByEvidence ?ev . }
  BIND(BOUND(?ev) AS ?hasEvidence)
  FILTER(
    (?evidenceStatus = ficr:EvidenceMissing && BOUND(?ev)) ||
    (?evidenceStatus = ficr:EvidenceAvailable && !BOUND(?ev))
  )
}


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?finding ?unit ?scenario ?ba ?conditionState ?evidenceStatus ?evidence
WHERE {
  ?finding a ficr:RiskFinding ;
           ficr:concernsRiskUnit ?unit ;
           ficr:derivedFromScenario ?scenario .
  ?scenario ficr:dependsOnBoundaryCondition ?ba .
  ?ba ficr:appliesToRiskUnit ?unit ;
      ficr:hasConditionState ?conditionState ;
      ficr:hasEvidenceStatus ?evidenceStatus .
  OPTIONAL { ?ba ficr:supportedByEvidence ?evidence . }
}
ORDER BY ?unit ?ba


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?event ?task ?taskLabel ?start ?end ?assessment
WHERE {
  ?event a ?eventType .
  FILTER(?eventType IN (ficr:RoutineTriggerEvent, ficr:AnomalyTriggerEvent,
                        ficr:ComplianceRequestTriggerEvent))
  ?event ficr:triggersTask ?task .
  OPTIONAL { ?task rdfs:label ?taskLabel . }
  OPTIONAL { ?task ficr:plannedStartTime ?start . }
  OPTIONAL { ?task ficr:plannedEndTime ?end . }
  OPTIONAL { ?task ficr:producesAssessment ?assessment . }
}
ORDER BY ?start


# ---------------------------------------------------------------------------

PREFIX ficr: <https://w3id.org/ficr#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?assessment ?finding ?result ?req ?clause
WHERE {
  ?assessment a ficr:ComplianceChecking ;
              ficr:producesFinding ?finding .
  ?finding ficr:hasComplianceResult ?result ;
           ficr:checksRequirement ?req .
  OPTIONAL { ?req ficr:hasClauseReference ?clause . }
}
ORDER BY ?result ?req ?finding
